const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
return [{ json: {
  db06_id: p.id.replace(/-/g, ''),
  ai_mode: p.properties['ai模式']?.select?.name || '',
  execute_idea_db06: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: (function(){ var T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"]; for(var i=0;i<T.length;i++){var a=p.properties[T[i]]?.relation||[]; if(a.length) return (a[0].id||'').replace(/-/g,'');} return ''; })(),
  target_rel: (function(){ var T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"]; for(var i=0;i<T.length;i++){var a=p.properties[T[i]]?.relation||[]; if(a.length) return T[i];} return ''; })(),
  mingxi_name: p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number
}}];

const item = $('Parse DB06').first().json;
const target = $input.first().json;
const tprops = target.properties || {};
const _tp = Object.values(tprops).find(v => v && v.type === 'title');
const target_name = (_tp?.title || []).map(t=>t.plain_text).join('') || '';
const target_idea = tprops['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '';
const target_theme = tprops['主題名稱']?.rich_text?.map(t=>t.plain_text).join('') || '';
const target_summary = tprops['簡介摘要']?.rich_text?.map(t=>t.plain_text).join('') || '';
const REL2XREF = {'對應提案':'提案引用','對應管考':'管考引用','對應項目':'項目引用','對應協作':'協作引用','對應內容':'內容引用','對應庫存':'庫存引用','對應對象':'對象引用','對應標籤':'對象引用','對應地點':'對象引用','對應提供對象':'對象引用'};
const xref_field = REL2XREF[item.target_rel] || '內容引用';
const idea = item.execute_idea_db06 || target_idea;
const parts = [target_name, target_theme, idea].map(s=>(s||'').trim()).filter(s=>s && s!=='(空)');
const query = ([...new Set(parts.join(' ').split(/\s+/))].join(' ')).slice(0,380) || target_name || '宜蘭 地方文化';
return [{ json: { query, db06_id:item.db06_id, db05_id:item.db05_id, ai_mode:item.ai_mode, sort_num:item.sort_num, mingxi_name:item.mingxi_name, target_rel:item.target_rel, xref_field, target_name } }];

const resp = $input.first().json;
const prompt = $('Build search prompt').first().json;
let results = Array.isArray(resp.results) ? resp.results.slice(0,20) : [];
const seen = new Set();
results = results.filter(r => { const u=(r.url||'').toString().trim(); if(!u||seen.has(u))return false; seen.add(u); return true; });
const count = results.length;
const sanitize = s => (s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/\s+/g,' ').trim().slice(0,500);
const dist = {};
for (const r of results) { let h='其他'; try{ h=new URL(r.url).hostname.replace(/^www\./,''); }catch(e){} dist[h]=(dist[h]||0)+1; }
const dist_line = Object.entries(dist).map(([k,v])=>k+'×'+v).join('、') || '—';
const usage_line = 'Tavily 採集 ' + count + ' 筆';
const d = new Date(); const tw = new Date(d.getTime()+8*3600*1000);
const ts = tw.getUTCFullYear()+'-'+String(tw.getUTCMonth()+1).padStart(2,'0')+'-'+String(tw.getUTCDate()).padStart(2,'0')+' '+String(tw.getUTCHours()).padStart(2,'0')+':'+String(tw.getUTCMinutes()).padStart(2,'0');
const search_summary = '── '+ts+' 搜查 ──\n工作對象：'+(prompt.target_name||prompt.mingxi_name||'(未命名)')+'\n做了什麼：Tavily 搜尋「'+(prompt.query||'').slice(0,50)+'」,逐筆查重對應連結後寫入 DB06,共 '+count+' 筆資料參考、填 '+prompt.xref_field+'\n來源分佈：'+dist_line+'\n未做：—';
const meta = { db06_id:prompt.db06_id, db05_id:prompt.db05_id, ai_mode:prompt.ai_mode, sort_num:prompt.sort_num, mingxi_name:prompt.mingxi_name, target_rel:prompt.target_rel, xref_field:prompt.xref_field, count, search_summary, safe_summary:sanitize(search_summary), usage_line, dist_line, has_results: count>0 };
if (count === 0) return [{ json: { ...meta } }];
return results.map((r,i) => ({ json: { ...meta,
  r_title: (r.title || ('參考資料 '+(i+1))).toString().slice(0,180),
  r_url: (r.url || '').toString().slice(0,1800),
  r_summary: (r.content || '').toString().slice(0,1900) } }));

